#include <iostream>
#include <vector>
#include <climits>

int minCoins(std::vector<int>& coins, int amount) {
  std::vector<int> dp(amount + 1, INT_MAX);
  dp[0] = 0;
  for (int i = 1; i <= amount; i++) {
    for (int coin : coins) {
      if (coin <= i && dp[i - coin] != INT_MAX) {
        dp[i] = std::min(dp[i], dp[i - coin] + 1);
      }
    }
  }
  return dp[amount];
}

int main() {
  std::vector<int> coins = {1, 5, 10, 25};
  int amount = 48;
  std::cout << "Minimum coins needed: " << minCoins(coins, amount) << std::endl;
  return 0;
}
// Output: Minimum coins needed: 6

