using System;
using System.Linq;

class Program {
  static int MinCoins(int[] coins, int amount) {
    int[] dp = new int[amount + 1];
    Array.Fill(dp, int.MaxValue);
    dp[0] = 0;
    for (int i = 1; i <= amount; i++) {
      foreach (int coin in coins) {
        if (coin <= i && dp[i - coin] != int.MaxValue) {
          dp[i] = Math.Min(dp[i], dp[i - coin] + 1);
        }
      }
    }
    return dp[amount];
  }

  static void Main() {
    int[] coins = {1, 5, 10, 25};
    int amount = 48;
    Console.WriteLine("Minimum coins needed: " + MinCoins(coins, amount));
  }
}
// Output: Minimum coins needed: 6

